local ia = game:GetService("HttpService")
local py = {}
function py.keys(fd)
	local dx = table.create(#fd)
	for ej in pairs(fd) do
		dx[#dx + 1] = ej
	end
	return dx
end
function py.values(fd)
	local dx = table.create(#fd)
	for ev, d3 in pairs(fd) do
		dx[#dx + 1] = d3
	end
	return dx
end
function py.entries(fd)
	local dx = table.create(#fd)
	for ej, d3 in pairs(fd) do
		dx[#dx + 1] = { ej, d3 }
	end
	return dx
end
function py.assign(pz, ...)
	for k2 = 1, select("#", ...) do
		local pA = select(k2, ...)
		if type(pA) == "table" then
			for ej, d3 in pairs(pA) do
				pz[ej] = d3
			end
		end
	end
	return pz
end
function py.copy(fd)
	local dx = table.create(#fd)
	for gX, bM in pairs(fd) do
		dx[gX] = bM
	end
	return dx
end
local function pB(fd, pC)
	local dx = table.create(#fd)
	pC[fd] = dx
	for gX, bM in pairs(fd) do
		if type(gX) == "table" then
			gX = pC[gX] or pB(gX, pC)
		end
		if type(bM) == "table" then
			bM = pC[bM] or pB(bM, pC)
		end
		dx[gX] = bM
	end
	return dx
end
function py.deepCopy(fd)
	return pB(fd, {})
end
function py.deepEquals(hD, dG)
	for gX in pairs(hD) do
		local pD = hD[gX]
		local pE = dG[gX]
		if type(pD) == "table" and type(pE) == "table" then
			local dx = py.deepEquals(pD, pE)
			if not dx then
				return false
			end
		elseif pD ~= pE then
			return false
		end
	end
	for gX in pairs(dG) do
		if hD[gX] == nil then
			return false
		end
	end
	return true
end
function py.toString(hG)
	return ia:JSONEncode(hG)
end
function py.isEmpty(fd)
	return next(fd) == nil
end
function py.fromEntries(pF)
	local pG = #pF
	local dx = table.create(pG)
	if pF then
		for k2 = 1, pG do
			local pH = pF[k2]
			dx[pH[1]] = pH[2]
		end
	end
	return dx
end
return py
